import React from "react";
import { Row, Col, Tabs, Typography, Card, Button } from "antd";
import { HeartOutlined, RightOutlined } from "@ant-design/icons";
import { useNavigate } from "react-router-dom";

const { Title, Paragraph } = Typography;
const { TabPane } = Tabs;

const Destinations = ({ tours }) => {
  const navigate = useNavigate();

  const filteredTours = {
    all: tours,
    b: tours.filter((tour) => tour.domain === "b"),
    t: tours.filter((tour) => tour.domain === "t"),
    n: tours.filter((tour) => tour.domain === "n"),
  };

  const renderTours = (list) => (
    <Row gutter={[16, 16]} justify="center">
      {list.map((tour, index) => (
        <Col
          key={tour.tourId}
          xs={24}
          sm={12}
          md={index % 3 === 2 ? 12 : 6}
          className={`domain-${tour.domain}`}
        >
          <Card
            hoverable
            cover={
              <div
                style={{
                  position: "relative",
                  maxHeight: 250,
                  overflow: "hidden",
                }}
              >
                <Button
                  type="text"
                  icon={<HeartOutlined style={{ color: "red" }} />}
                  style={{ position: "absolute", top: 8, right: 8, zIndex: 1 }}
                />
                <img
                  alt="Destination"
                  src={`/client/public/assets/`}
                  style={{ width: "100%", objectFit: "cover", maxHeight: 250 }}
                />
              </div>
            }
          >
            <h6 className="tour-title">
              <a onClick={() => navigate(`/tours/${tour.tourId}`)}>
                {tour.title}
              </a>
            </h6>
            <span className="time">{tour.time}</span>
            <Button
              type="link"
              icon={<RightOutlined />}
              onClick={() => navigate(`/tours/${tour.tourId}`)}
            />
          </Card>
        </Col>
      ))}
    </Row>
  );

  return (
    <section style={{ padding: "100px 0 90px", background: "#fff" }}>
      <div className="container">
        <div className="text-center mb-4">
          <Title level={2}>Khám phá các điểm đến phổ biến</Title>
          <Paragraph>
            Website <strong>34500</strong> trải nghiệm phổ biến nhất mà bạn sẽ
            nhớ
          </Paragraph>
        </div>
        <Tabs defaultActiveKey="all" centered>
          <TabPane tab="Tất cả" key="all">
            {renderTours(filteredTours.all)}
          </TabPane>
          <TabPane tab="Miền Bắc" key="b">
            {renderTours(filteredTours.b)}
          </TabPane>
          <TabPane tab="Miền Trung" key="t">
            {renderTours(filteredTours.t)}
          </TabPane>
          <TabPane tab="Miền Nam" key="n">
            {renderTours(filteredTours.n)}
          </TabPane>
        </Tabs>
      </div>
    </section>
  );
};

export default Destinations;
